var e=[{id:`L3_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`연락 받았어. 다들 다치진 않았어?`,JPN:`連絡を貰ったよ。みんな怪我は？`,ENG:`I got the message. Is everyone all right?`,TWN:`我收到消息了，大家沒受傷吧？`},stage:{bg:`CAR`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`우린 괜찮네. 아직까지는 말이야.`,JPN:`こっちは大丈夫だ。まだ今はな。`,ENG:`We're okay. For now, at least.`,TWN:`我們目前沒事，之後不好說。`},stage:{bg:`CAR`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`지금 그쪽으로 가는 중이야. 조금만 더…….`,JPN:`今そっちに向かってる。あともう少し……`,ENG:`We're heading your way. Almost there–`,TWN:`我現在正往你們的位置移動，再等一下……`},stage:{bg:`CAR`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`꺄악?!`,JPN:`キャーッ！？`,ENG:`Kyaak!`,TWN:`啊啊？！`},stage:{bg:`CAR`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`괜찮나, 스키너 양?`,JPN:`大丈夫か、スキナー君？`,ENG:`Skinner, are you okay?`,TWN:`史金納，你沒事吧？`},stage:{bg:`CAR`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`네? 네, 잡아 주신 덕분에…….`,JPN:`えっ？　はい、支えてくださったので……`,ENG:`Huh? Oh, yes. Thanks to you...`,TWN:`嗯？幸好你抓住我……`},stage:{bg:`CAR`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`쳇, 침식 쐐기와 정면충돌했습니다.`,JPN:`ちぇっ、侵食楔と正面衝突しました。`,ENG:`Tch! We've been hit with a Corrupted Wedge.`,TWN:`嘖，和侵食楔正面衝突。`},stage:{bg:`CAR`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`저, 저기 뒤에! 침식체들이 몰려와요!`,JPN:`あの、あの後ろに！　侵食体が押し寄せて来ています！`,ENG:`L-look behind you! C.O.s are coming!`,TWN:`後，後面！！侵蝕體撲過來了！`},stage:{bg:`CAR`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`탈출해야겠네요. 꽉 잡으세요.`,JPN:`脱出しなければ。捕まってください。`,ENG:`We need to get out of here. Hang on tight.`,TWN:`要趕快離開這裡，抓緊了。`},stage:{bg:`CAR`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`두 분 다 괜찮으신가요?`,JPN:`お二人とも大丈夫でしょうか？`,ENG:`You two okay back there?`,TWN:`你們還好嗎？`},stage:{bg:`DONGDAEMUN_CLOUDY`,slots:{L:null,C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`폭발물 전문가가 의뢰인을 폭발 위험에 노출시키다니, 부끄러워서 몸 둘 바를 모르겠군요.`,JPN:`爆発物の専門家である私が依頼人を爆発の危険に晒すなんて、お恥ずかしい限りです。`,ENG:`I can't believe I got my client exposed to an explosion. I feel so ashamed of myself as an explosive expert.`,TWN:`真是羞愧，我身為炸彈專家，卻讓委託人落在爆炸的危險之中。`},stage:{bg:`DONGDAEMUN_CLOUDY`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`전 괜찮아요. 구해주셔서 감사해요, 초원 씨.`,JPN:`私は大丈夫です。助けていただきありがとうございます、スズキ・ナオさん。`,ENG:`I'm okay. Thank you for saving us, Miss Chowon.`,TWN:`我沒事，謝謝初源出手相救。`},stage:{bg:`DONGDAEMUN_CLOUDY`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`마치 기다리고 있었던 것처럼 침식 쐐기가 차 앞을 가로막더군.`,JPN:`まるで待っていたかのように侵食楔が車の行く手を阻んできた。`,ENG:`They blocked off our route with a Corrupted Wedge as if they were waiting for us.`,TWN:`侵食楔彷彿在等我們似地擋下我們的車。`},stage:{bg:`DONGDAEMUN_CLOUDY`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L28_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`일반적인 움직임은 아닐세.`,JPN:`普通の動きではない。`,ENG:`It's not their normal behavior.`,TWN:`是刻意的。`},stage:{bg:`DONGDAEMUN_CLOUDY`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`그렇다면…… 저희를 노리기라도 한다는 건가요?`,JPN:`つまり……私たちを狙っているのでしょうか？`,ENG:`Then... are you saying they're after us?`,TWN:`難道是……針對我們來的？`},stage:{bg:`DONGDAEMUN_CLOUDY`,slots:{L:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};